const https = require('https');
const http = require('http');

const feeds = [
  { url: 'https://www.infomoney.com.br/feed/', category: 'mercado_economia' },
  { url: 'https://valor.globo.com/rss/home.xml', category: 'mercado_economia' },
  { url: 'https://www.cnnbrasil.com.br/economia/feed/', category: 'mercado_economia' },
  { url: 'https://feeds.folha.uol.com.br/mercado/rss091.xml', category: 'mercado_economia' },
  { url: 'https://g1.globo.com/rss/g1/politica/feed.xml', category: 'politica_brasil' },
  { url: 'https://agenciabrasil.ebc.com.br/rss/ultimasnoticias/feed.xml', category: 'politica_brasil' },
  { url: 'https://feeds.folha.uol.com.br/brasil/rss091.xml', category: 'politica_brasil' },
  { url: 'https://rss.uol.com.br/feed/noticias.xml', category: 'politica_brasil' },
  { url: 'https://www.technologyreview.com/feed/', category: 'ia_tecnologia' },
  { url: 'https://techcrunch.com/feed/', category: 'ia_tecnologia' },
  { url: 'https://www.theverge.com/rss/index.xml', category: 'ia_tecnologia' },
  { url: 'https://feeds.arstechnica.com/arstechnica/index', category: 'ia_tecnologia' },
  { url: 'https://olhardigital.com.br/feed/', category: 'ia_tecnologia' },
  { url: 'https://www.lennysnewsletter.com/feed', category: 'produto_growth' },
  { url: 'https://www.dwarkeshpatel.com/feed', category: 'produto_growth' },
];

function fetchUrl(url, redirects = 0) {
  return new Promise((resolve, reject) => {
    if (redirects > 3) return reject(new Error('too many redirects'));
    const lib = url.startsWith('https') ? https : http;
    const req = lib.get(url, { timeout: 15000, headers: { 'User-Agent': 'Mozilla/5.0 newsletter-agent/1.0' } }, (res) => {
      if (res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
        return fetchUrl(res.headers.location, redirects + 1).then(resolve).catch(reject);
      }
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => resolve(data));
    });
    req.on('error', reject);
    req.on('timeout', () => { req.destroy(); reject(new Error('timeout')); });
  });
}

function cleanText(str) {
  return str.replace(/<[^>]+>/g, '').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"').replace(/&#39;/g, "'").replace(/\s+/g, ' ').trim();
}

function parseField(block, tag) {
  const m = block.match(new RegExp('<' + tag + '[^>]*>(?:<!\\[CDATA\\[)?([\\s\\S]*?)(?:\\]\\]>)?<\\/' + tag + '>', 'i'));
  return m ? cleanText(m[1]) : '';
}

function parseFeed(xml, category) {
  const articles = [];
  const rssRe = /<item[^>]*>([\s\S]*?)<\/item>/gi;
  const atomRe = /<entry[^>]*>([\s\S]*?)<\/entry>/gi;
  let match;

  while ((match = rssRe.exec(xml)) !== null) {
    const b = match[1];
    const title = parseField(b, 'title');
    if (!title) continue;
    const description = parseField(b, 'description').substring(0, 280);
    const link = parseField(b, 'link') || (b.match(/<link>([\s\S]*?)<\/link>/) || [])[1]?.trim() || '';
    const pubDate = parseField(b, 'pubDate');
    articles.push({ title, description, link, pubDate, category });
  }

  if (articles.length === 0) {
    while ((match = atomRe.exec(xml)) !== null) {
      const b = match[1];
      const title = parseField(b, 'title');
      if (!title) continue;
      const description = (parseField(b, 'summary') || parseField(b, 'content')).substring(0, 280);
      const linkMatch = b.match(/<link[^>]+href=["']([^"']+)["']/i);
      const link = linkMatch ? linkMatch[1] : '';
      const pubDate = parseField(b, 'published') || parseField(b, 'updated');
      articles.push({ title, description, link, pubDate, category });
    }
  }

  return articles;
}

const results = await Promise.allSettled(
  feeds.map(async ({ url, category }) => {
    try {
      const xml = await fetchUrl(url);
      return parseFeed(xml, category);
    } catch (e) {
      return [];
    }
  })
);

const allArticles = results.flatMap(r => r.status === 'fulfilled' ? r.value : []);
return allArticles.map(article => ({ json: article }));

const now = new Date();
const cutoff = new Date(now.getTime() - 24 * 60 * 60 * 1000);
const items = $input.all();

const filtered = items.filter(item => {
  const pd = item.json.pubDate;
  if (!pd) return true;
  const d = new Date(pd);
  return !isNaN(d.getTime()) && d >= cutoff;
});

// Fallback: se filtro zerou tudo, retorna os 20 mais recentes
if (filtered.length === 0) return items.slice(0, 20);
return filtered;

const https = require('https');

const notionToken = 'YOUR_NOTION_TOKEN';
const parentPageId = 'YOUR_NOTION_PARENT_PAGE_ID';

const claudeText = $json.content[0].text;
const today = new Date();
const dd = String(today.getDate()).padStart(2, '0');
const mm = String(today.getMonth() + 1).padStart(2, '0');
const title = `Atualize Hoje - ${dd}/${mm}`;

function makeBlock(type, content) {
  return { object: 'block', type, [type]: content };
}

function rt(text, bold, italic) {
  const obj = { type: 'text', text: { content: text.substring(0, 2000) } };
  if (bold || italic) obj.annotations = { bold: !!bold, italic: !!italic };
  return [obj];
}

function para(text, bold, italic) {
  return makeBlock('paragraph', { rich_text: rt(text, bold, italic) });
}

function h2(text) { return makeBlock('heading_2', { rich_text: rt(text) }); }
function h3(text) { return makeBlock('heading_3', { rich_text: rt(text) }); }

function callout(text, emoji) {
  return makeBlock('callout', { rich_text: rt(text), icon: { type: 'emoji', emoji } });
}

function qblock(text) { return makeBlock('quote', { rich_text: rt(text) }); }
function divider() { return makeBlock('divider', {}); }
function bullet(text) { return makeBlock('bulleted_list_item', { rich_text: rt(text) }); }

const lines = claudeText.split('\n');
const blocks = [];

for (const line of lines) {
  const t = line.trim();
  if (!t) continue;

  if (t === '---') { blocks.push(divider()); continue; }

  if (t.startsWith('## ')) { blocks.push(h2(t.slice(3))); continue; }

  if (/^\*\*[^*]+\*\*$/.test(t)) { blocks.push(h3(t.replace(/\*\*/g, ''))); continue; }

  if (t.startsWith('💡')) { blocks.push(callout(t.replace(/^💡\s*/, ''), '💡')); continue; }

  if (t.startsWith('Bom dia')) { blocks.push(callout(t, '🌅')); continue; }

  if (t.startsWith('_') && t.endsWith('_')) { blocks.push(para(t.slice(1, -1), false, true)); continue; }

  if (t.startsWith('—') || t.startsWith('–') || t.startsWith('—')) {
    blocks.push(para('— ' + t.replace(/^[—–]\s*/, '').replace(/\*\*/g, ''), false, true));
    continue;
  }

  if (t.startsWith('"') || t.startsWith('“')) { blocks.push(qblock(t)); continue; }

  if (t.startsWith('- ')) { blocks.push(bullet(t.slice(2))); continue; }

  if (t.includes('**')) { blocks.push(para(t.replace(/\*\*/g, ''))); continue; }

  let rem = t;
  while (rem.length > 0) {
    blocks.push(para(rem.substring(0, 2000)));
    rem = rem.substring(2000);
  }
}

function notionReq(method, path, body) {
  return new Promise((resolve, reject) => {
    const bodyStr = JSON.stringify(body);
    const opts = {
      hostname: 'api.notion.com', port: 443, path, method,
      headers: {
        'Authorization': `Bearer ${notionToken}`,
        'Content-Type': 'application/json',
        'Notion-Version': '2022-06-28',
        'Content-Length': Buffer.byteLength(bodyStr)
      }
    };
    const req = https.request(opts, (res) => {
      let raw = '';
      res.on('data', c => raw += c);
      res.on('end', () => {
        try {
          const parsed = JSON.parse(raw);
          if (res.statusCode < 200 || res.statusCode >= 300)
            reject(new Error(`Notion ${res.statusCode}: ${JSON.stringify(parsed)}`));
          else resolve(parsed);
        } catch(e) { reject(e); }
      });
    });
    req.on('error', reject);
    req.write(bodyStr);
    req.end();
  });
}

const page = await notionReq('POST', '/v1/pages', {
  parent: { page_id: parentPageId },
  icon: { type: 'emoji', emoji: '📰' },
  properties: { title: [{ text: { content: title } }] },
  children: blocks.slice(0, 100)
});

for (let i = 100; i < blocks.length; i += 100) {
  await notionReq('PATCH', `/v1/blocks/${page.id}/children`, { children: blocks.slice(i, i + 100) });
}

return [{ json: { notion_url: page.url, notion_page_id: page.id, title, status: 'saved' } }];
